// 感染 开场变量初始化 v1.1
// 从 alternate_greeting 的 <UpdateVariable><JSONPatch> 块初始化 stat_data
(async () => {
  await waitGlobalInitialized('TavernHelper');
  await waitGlobalInitialized('Mvu');

  function initFromGreeting() {
    try {
      const ctx = SillyTavern.getContext();
      if (!ctx || !Array.isArray(ctx.chat) || !ctx.chat[0]) return;
      const mes = ctx.chat[0];
      if (!mes || typeof mes.mes !== 'string') return;
      const stat = TavernHelper.variables.stat_data;
      if (stat && stat.user_profile && stat.user_profile.origin_identity && stat.user_profile.origin_identity !== '') return;
      const m = mes.mes.match(/<UpdateVariable>[\\s\\S]*?<JSONPatch>([\\s\\S]*?)<\\/JSONPatch>[\\s\\S]*?<\\/UpdateVariable>/i);
      if (!m) return;
      const patches = JSON.parse(m[1].trim());
      if (!Array.isArray(patches)) return;
      const data = stat || {};
      for (const p of patches) {
        if (p.op === 'replace' || p.op === 'add') {
          const parts = p.path.replace(/^\\//, '').split('/');
          let cur = data;
          for (let i = 0; i < parts.length - 1; i++) {
            if (typeof cur[parts[i]] !== 'object' || cur[parts[i]] === null) cur[parts[i]] = {};
            cur = cur[parts[i]];
          }
          cur[parts[parts.length - 1]] = p.value;
        }
      }
      if (!stat) TavernHelper.variables.stat_data = data;
      if (typeof Mvu.notifyUpdate === 'function') Mvu.notifyUpdate();
    } catch (e) { /* silent */ }
  }

  function onChatLoaded() {
    setTimeout(initFromGreeting, 500);
  }

  try { eventOn('chat_id_changed', onChatLoaded); } catch (e) {}
  try { eventOn('message_rendered', onChatLoaded); } catch (e) {}
  try { if (Mvu && typeof Mvu.eventOn === 'function') Mvu.eventOn('mag_variable_initiailized', initFromGreeting); } catch (e) {}
  setTimeout(onChatLoaded, 1500);
})();
